---@class UIHeroTreeRoot
local UIHeroTreeRoot = LxClass("UIHeroTreeRoot",nil)

function UIHeroTreeRoot:UIHeroTreeRoot()
    ---@type LWnd
    self._wndClass = nil

    ---@type Transform
    self._transRoot = nil

    ---@type Transform
    self._ScrollRect = nil

    ---@type Transform
    self._ContentTrans = nil

    ---@type Transform
    self._PointListRoot = nil

    ---@type Transform
    self._LineListRoot = nil

    self._recordEffectMap = {}

    self:InitData()
end

function UIHeroTreeRoot:InitData()
    --- 英雄觉醒树数据
    self._treeInfoList = {}

    --- 节点数据
    self._treeTransInfoList = {}

    --- 预制体节点名称
    self._recordTreePbNode = {}

    --- 预制体节点名称
    self._recordActTreeMap = {}

    --- 线节点数据
    self._lineTransInfoList = {}

    ---@type StructHero
    self._heroData = nil

    ---@type string
    self._heroId = nil

    ---@type number
    self._treeRefId = nil

    --- 当前激活的refId
    self._curActTreeRefId = nil

    --- 当前激活的refId
    self._curSelTreeRefId = nil

    self._curTreeIsMax = false

    self._iconHd = nil
    self._iconHdGray = "heroup_road_skill"
end

function UIHeroTreeRoot:Destroy()
    if self:IsDestroy() then return end
    self._isDestroy = true
    table.removeall(self)
end

function UIHeroTreeRoot:IsDestroy()
    return self._isDestroy
end

function UIHeroTreeRoot:IsWndValid()
    return self._wndClass and self._wndClass:IsWndValid()
end



---@param wndClass LWnd
---@param transRoot Transform
---@param heroData StructHero
function UIHeroTreeRoot:SetInfo(wndClass,transRoot,heroData)
    self:InitData()
    self._wndClass = wndClass
    self._transRoot = transRoot
    self._heroData = heroData
    self._heroId = heroData:GetId()
    self._treeRefId = heroData:GetTreeRefId()

    self._iconHd = gModelHero:GetHeroTreeIconHd(self._treeRefId)

    self:InitHeroTreeInfoList()
    self:InitTrans()
    self:MoveToActPoint()
end

--- 初始化数据
function UIHeroTreeRoot:InitHeroTreeInfoList()
    if not self._heroData then return end
    self._treeInfoList = gModelHero:GetServerHeroTreeInfoByHeroId(self._heroId)
    self:RefreshCurActTreeRefId()
end

function UIHeroTreeRoot:RefreshCurActTreeRefId()
    local maxPointRefId
    local points = gModelHero:GetHeroServerTreePoints(self._heroId,true)
    if #points > 0 then
        local list = {}
        for i,v in ipairs(points) do
            table.insert(list,{
                pointRefId = v.pointRefId,
                lvRefId = v.lvRefId,
                skillId = v.skillId,
            })
        end
        table.sort(list,function(a,b)
            return a.pointRefId > b.pointRefId
        end)
        maxPointRefId = list[1].pointRefId
    end
    local isMaxLv = false
    local curActTreeRefId
    local treePointList = gModelHero:GetHeroTreePointList(self._treeRefId)
    if maxPointRefId then
        for i,v in ipairs(treePointList) do
            if maxPointRefId < v.refId then
                curActTreeRefId = v.refId
                break
            end
        end
        if not curActTreeRefId then
            isMaxLv = true
        end
    else
        curActTreeRefId = treePointList[1].refId
    end
    self._curActTreeRefId = curActTreeRefId
    self._curSelTreeRefId = curActTreeRefId
    self._curTreeIsMax = isMaxLv
end

--- 初始化节点
function UIHeroTreeRoot:InitTrans()
    if not self:IsWndValid() then return end
    if not self._transRoot then return end

    local transRoot = self._transRoot
    local wndClass = self._wndClass
    local BgEff = wndClass:FindWndTrans(transRoot,"Bg/BgEff")
    wndClass:CreateWndEffect(BgEff,"fx_ui_awakenree","fx_ui_awakenree",100)

    local ScrollRect = wndClass:FindWndTrans(transRoot,"ScrollRect")
    self._ScrollRect = ScrollRect
    local ContentTrans = wndClass:FindWndTrans(ScrollRect,"Content")
    self._ContentTrans = ContentTrans
    local PointListRoot = wndClass:FindWndTrans(ContentTrans,"PointList")
    local LineListRoot = wndClass:FindWndTrans(ContentTrans,"LineList")
    self._PointListRoot = PointListRoot
    self:InitPointTrans()

    self._LineListRoot = LineListRoot
    self:InitLineTrans()
end

function UIHeroTreeRoot:InitPointTrans()
    if not self:IsWndValid() then return end

    local treeInfoList = self._treeInfoList
    if not treeInfoList then return end

    local PointListRoot = self._PointListRoot
    if not PointListRoot then return end

    for k,v in pairs(treeInfoList) do
        self:SetAwakenTreeRoot(PointListRoot,v)
    end

    table.sort(self._recordTreePbNode,function(a,b) return a < b end)
end

function UIHeroTreeRoot:SetAwakenTreeRoot(trans,itemdata)
    if not self:IsWndValid() then return end

    local treePointRefId = itemdata.treePointRefId
    local pointRef = gModelHero:GetHeroTreePointRef(treePointRefId)
    if not pointRef then return end

    local wndClass = self._wndClass
    local treePbNode = pointRef.treePbNode
    local pointTrans = wndClass:FindWndTrans(trans, treePbNode)
    if not pointTrans then return end

    table.insert(self._recordTreePbNode,treePbNode)

    self._recordActTreeMap[tonumber(treePbNode)] = itemdata.isActivate

    local transInfo
    local pointType = itemdata.pointType
    if pointType == ModelHero.TREE_POINT_TYPE_ATTR then
        transInfo = self:_DisposeSPoint(pointTrans,itemdata)
        wndClass:SetWndClick(transInfo.root,function()
            self:_OnClickAttrIconFunc(itemdata)
        end)
    elseif pointType == ModelHero.TREE_POINT_TYPE_SKILL then
        transInfo = self:_DisposeBPoint(pointTrans,itemdata)
        wndClass:SetWndClick(transInfo.root,function()
            self:_OnClickSkillIconFunc(itemdata)
        end)
        wndClass:SetWndClick(transInfo.BtnChangeSkill,function()
            self:_OnClickBtnChangeSkill(itemdata)
        end)
    end
    if transInfo and transInfo.NewItemIcon then
        wndClass:SetTextTile(transInfo.NewItemIcon,ccClientText(20182))
    end
    self._treeTransInfoList[treePointRefId] = transInfo
    self:RefreshPointTrans(transInfo,itemdata)
    return true
end

function UIHeroTreeRoot:_OnClickAttrIconFunc(itemdata)
    if gModelHeroExtra:IsTreeSkillMore() then
        if self:IsWndValid() then
            self._curSelTreeRefId = itemdata.treePointRefId
            self:RefreshCurSelState()
            FireEvent(EventNames.ON_HEROTREE_CHANGESEL)
        end
    end
end

function UIHeroTreeRoot:_OnClickSkillIconFunc(itemdata)
    local skillId = self:GetSkillId(itemdata,true)
    if not skillId then return end
    if gModelHeroExtra:IsTreeSkillMore() then
        if self:IsWndValid() then
            self._curSelTreeRefId = itemdata.treePointRefId
            self:RefreshCurSelState()
            FireEvent(EventNames.ON_HEROTREE_CHANGESEL)
        end
    else
        gModelGeneral:OpenSkillWnd({curSkillId = skillId,wndType = 2})
    end
end

function UIHeroTreeRoot:_OnClickBtnChangeSkill(itemdata)
    GF.OpenWnd("UISagaTreeCGjeJN", {
        heroId = self._heroId,
        pointRefId = itemdata.treePointRefId,
        actLvRefId = itemdata.lvRefId,
    })
end

function UIHeroTreeRoot:_DisposeBPoint(trans,itemdata)
    if not self:IsWndValid() then return end
    local wndClass = self._wndClass
    local ItemBg = wndClass:FindWndTrans(trans,"ItemBg")
    local Empty = wndClass:FindWndTrans(trans,"Empty")
    local ItemIconMask = wndClass:FindWndTrans(trans,"ItemIconMask")
    local ItemIcon = wndClass:FindWndTrans(ItemIconMask,"ItemIcon")
    local BtnChangeSkill = wndClass:FindWndTrans(trans,"BtnChangeSkill")
    local ItemIconGray = wndClass:FindWndTrans(trans,"ItemIconGray")
    local ItemIconKuang = wndClass:FindWndTrans(trans,"ItemIconKuang")
    local SelectIcon = wndClass:FindWndTrans(trans,"SelectIcon")
    local EffRoot = wndClass:FindWndTrans(trans,"EffRoot")
    local NewItemIcon = wndClass:FindWndTrans(trans,"NewItemIcon")
    local NameBg = wndClass:FindWndTrans(trans,"NameBg")
    local NameText = wndClass:FindWndTrans(NameBg,"UIText")
    if not string.isempty(self._iconHd) then
        wndClass:SetWndEasyImage(ItemIconKuang,self._iconHd,nil,true)
    end
    return {
        root = trans,
        ItemBg = ItemBg,
        Empty = Empty,
        ItemIconMask = ItemIconMask,
        ItemIcon = ItemIcon,
        BtnChangeSkill = BtnChangeSkill,
        ItemIconGray = ItemIconGray,
        ItemIconKuang = ItemIconKuang,
        SelectIcon = SelectIcon,
        EffRoot = EffRoot,
        NewItemIcon = NewItemIcon,
        NameBg = NameBg,
        NameText = NameText,
        pointType = itemdata.pointType
    }
end

function UIHeroTreeRoot:_DisposeSPoint(trans,itemdata)
    if not self:IsWndValid() then return end
    local wndClass = self._wndClass
    local ItemBg = wndClass:FindWndTrans(trans,"ItemBg")
    local ItemIconMask = wndClass:FindWndTrans(trans,"ItemIconMask")
    local ItemIcon = wndClass:FindWndTrans(ItemIconMask,"ItemIcon")
    local SelectIcon = wndClass:FindWndTrans(trans,"SelectIcon")
    local EffRoot = wndClass:FindWndTrans(trans,"EffRoot")
    local NewItemIcon = wndClass:FindWndTrans(trans,"NewItemIcon")
    local NewItemText = wndClass:FindWndTrans(NewItemIcon,"UIText")
    local NameBg = wndClass:FindWndTrans(trans,"NameBg")
    local NameText = wndClass:FindWndTrans(NameBg,"UIText")
    return {
        root = trans,
        ItemBg = ItemBg,
        ItemIconMask = ItemIconMask,
        ItemIcon = ItemIcon,
        SelectIcon = SelectIcon,
        EffRoot = EffRoot,
        NewItemIcon = NewItemIcon,
        NewItemText = NewItemText,
        NameBg = NameBg,
        NameText = NameText,
        pointType = itemdata.pointType
    }
end

function UIHeroTreeRoot:InitLineTrans()
    if not self:IsWndValid() then return end

    if #self._recordTreePbNode < 0 then return end

    local LineListRoot = self._LineListRoot
    if not LineListRoot then return end

    local wndClass = self._wndClass

    local actNum,transName
    local recordTreePbNode = self._recordTreePbNode
    local len = #recordTreePbNode
    for i = 1, len-1 do
        actNum = i + 1
        transName = string.replace("Line#a1#-#a2#",i,actNum)
        local trans = wndClass:FindWndTrans(LineListRoot,transName)
        self._lineTransInfoList[actNum] = {
            root = trans,
            LineActTrans = wndClass:FindWndTrans(trans,"LineAct"),
        }
    end
    self:RefreshLineState()
end

function UIHeroTreeRoot:RefreshLineState()
    if not self:IsWndValid() then return end
    local showAct
    local recordActTreeMap = self._recordActTreeMap
    for k,v in pairs(self._lineTransInfoList) do
        showAct = recordActTreeMap[k]
        CS.ShowObject(v.LineActTrans,showAct)
    end
end

function UIHeroTreeRoot:MoveToActPoint()
    if not self:IsWndValid() then return end

    local wndClass = self._wndClass
    if not wndClass then return end

    local ScrollRect = self._ScrollRect
    if not ScrollRect then return end

    local ContentTrans = self._ContentTrans
    if not ContentTrans then return end

    local moveHeight = 0
    local ScrollHeight = ScrollRect.rect.height
    local ContentHeight = ContentTrans.rect.height
    local isMaxLv = self:CheckTreeIsMax()
    if isMaxLv then
        moveHeight = ScrollHeight - ContentHeight
    else
        local curActTreeRefId = self:GetCurActTreeRefId()
        local treeTransInfoList = self._treeTransInfoList
        local treeTrans = treeTransInfoList[curActTreeRefId]
        if treeTrans then
            local root = treeTrans.root
            local rootHeight = root.rect.height
            local rootPos = ContentTrans:InverseTransformPoint(root.position)
            local posY = -(rootHeight + rootPos.y)
            if posY + ScrollHeight < 0 then
                moveHeight = posY + ScrollHeight - 100
            end
        end
    end
    local curPos = ContentTrans.localPosition
    wndClass:SetAnchorPos(ContentTrans,Vector3(curPos.x,moveHeight,curPos.z))
end

--- 刷新节点显示
function UIHeroTreeRoot:RefreshPointTrans(transInfo,itemdata)
    if not self:IsWndValid() then return end
    if not transInfo then return end

    local treeRefId = itemdata.treeRefId
    local treeRef = GameTable.CharacterTreeRef[treeRefId]

    local wndClass = self._wndClass

    local showSel = self:IsCurSelTreePointRefId(itemdata)
    CS.ShowObject(transInfo.SelectIcon,showSel)

    local showEffName
    local ItemIcon = transInfo.ItemIcon
    local pointType = itemdata.pointType
    local isActivate = itemdata.isActivate
    local needGray,showMask,showName = false,false,false
    if pointType == ModelHero.TREE_POINT_TYPE_ATTR then
        if isActivate then
            wndClass:SetWndEasyImage(ItemIcon,treeRef.icon1,function()
                CS.ShowObject(ItemIcon,true)
            end)
            showMask = true
        end
        if isActivate then
            showEffName = "fx_ui_awakenree_act"
        elseif showSel then
            showEffName = "fx_ui_awakenree_get"
        end
    elseif pointType == ModelHero.TREE_POINT_TYPE_SKILL then
        --- 技能需要显示遮罩
        needGray = not isActivate
        local sId = self:GetSkillId(itemdata)
        if sId then
            local skillRef = gModelHero:GetSkillByStarId(sId)
            if skillRef then
                showMask = true
                showName = true
                wndClass:SetWndEasyImage(ItemIcon,skillRef.icon,function()
                    CS.ShowObject(ItemIcon,true)
                end)
                wndClass:SetWndText(transInfo.NameText,ccLngText(skillRef.name))
            end
        end
        CS.ShowObject(transInfo.Empty,not showMask)
        local bgImg = isActivate and treeRef.icon2 or "heroup_road_01"
        wndClass:SetWndEasyImage(transInfo.ItemBg,bgImg,nil,true)
        if isActivate then
            showEffName = "fx_ui_awakenree_actskill"
        elseif showSel then
            showEffName = "fx_ui_awakenree_getskill"
        end
        CS.ShowObject(transInfo.ItemIconGray,needGray)
        CS.ShowObject(transInfo.ItemIconKuang,not needGray)

        local showChangeSkill = false
        ---2025/1/3： 未觉醒不显示切换按钮，下面可以看到
        if itemdata.isActivate then
            local lvList = itemdata.lvList
            if lvList and #lvList > 0 then
                local firstLvList = lvList[1]
                local skillList = firstLvList.skillList or {}
                showChangeSkill = #skillList > 1
            end
        end
        CS.ShowObject(transInfo.BtnChangeSkill,showChangeSkill)
    end

    local EffRoot = transInfo.EffRoot
    local hasEff = showEffName ~= nil
    if hasEff then
        local needCreateWndEff = true
        local key = EffRoot:GetInstanceID()
        local effKey = key .. "-" .. showEffName
        local recordEffectInfo = self._recordEffectMap[key]
        if recordEffectInfo then
            ---@type LDisplayEffect
            local oldEff
            local oldEffName,showEff
            for k,v in pairs(recordEffectInfo) do
                oldEff = wndClass:FindWndEffectByKey(k)
                if oldEff then
                    oldEffName = oldEff:GetEffectName()
                    showEff = oldEffName == showEffName
                    if showEff then
                        needCreateWndEff = false
                    end
                    oldEff:SetVisible(showEff)
                end
            end
        end
        if needCreateWndEff then
            self._recordEffectMap[key] = {
                [effKey] = true
            }
            wndClass:CreateWndEffect(EffRoot,showEffName,effKey,100)
        end
    end
    CS.ShowObject(EffRoot,hasEff)

    wndClass:SetWndImageGray(ItemIcon,needGray)
    CS.ShowObject(transInfo.ItemIconMask,showMask)

    local showNewIcon = self:IsShowSelect(itemdata)
    CS.ShowObject(transInfo.NewItemIcon,showNewIcon)

    CS.ShowObject(transInfo.NameBg,showName)
end

function UIHeroTreeRoot:GetSkillId(itemdata,ignoreNotAct)
    if not ignoreNotAct and not itemdata.isActivate then return end

    local lvList = itemdata.lvList
    if lvList and #lvList > 0 then
        local sId = nil
        local skillList
        local skillId = itemdata.skillId or 0
        for i,v in ipairs(lvList) do
            if sId then break end
            skillList = v.skillList or {}
            if #skillList > 0 then
                for _i,_v in ipairs(skillList) do
                    if _v >= skillId then
                        sId = _v
                        break
                    end
                end
            end
        end
        return sId
    end
end

function UIHeroTreeRoot:IsShowSelect(itemdata)
    return self._curActTreeRefId == itemdata.treePointRefId
end

function UIHeroTreeRoot:IsCurSelTreePointRefId(itemdata)
    return self._curSelTreeRefId == itemdata.treePointRefId
end

--- 获取当前的refId
function UIHeroTreeRoot:GetCurActTreeRefId()
    return self._curActTreeRefId
end

--- 获取当前的refId
function UIHeroTreeRoot:GetCurSelTreeRefId()
    return self._curSelTreeRefId
end

function UIHeroTreeRoot:CheckIsNextUpLv()
    return self._curActTreeRefId == self._curSelTreeRefId
end

function UIHeroTreeRoot:CheckTreeIsMax()
    return self._curTreeIsMax
end

function UIHeroTreeRoot:RefreshHeroTree()
    if not self:IsWndValid() then return end

    self:InitHeroTreeInfoList()

    local treeInfoList = self._treeInfoList
    if not treeInfoList then return end

    local treeTransInfoList = self._treeTransInfoList
    if not treeTransInfoList then return end

    for k,v in pairs(treeInfoList) do
        self:RefreshPointTrans(treeTransInfoList[v.treePointRefId],v)
    end
end

function UIHeroTreeRoot:RefreshHeroSkillShow()
    if not self._heroData then return end
    self._treeInfoList = gModelHero:GetServerHeroTreeInfoByHeroId(self._heroId)

    local treeInfoList = self._treeInfoList
    if not treeInfoList then return end

    local treeTransInfoList = self._treeTransInfoList
    if not treeTransInfoList then return end

    for k,v in pairs(treeInfoList) do
        self:RefreshPointTrans(treeTransInfoList[v.treePointRefId],v)
    end
end

function UIHeroTreeRoot:RefreshCurSelState()
    local treeInfoList = self._treeInfoList
    if not treeInfoList then return end

    local treeTransInfoList = self._treeTransInfoList
    if not treeTransInfoList then return end

    for k,v in pairs(treeInfoList) do
        local transInfo = treeTransInfoList[v.treePointRefId]
        if transInfo then
            local showSel = self:IsCurSelTreePointRefId(v)
            CS.ShowObject(transInfo.SelectIcon,showSel)
        end
    end
end

return UIHeroTreeRoot